                    for j in range(i, min(len(lines), i+8)):
                        next_line = lines[j]
                        if 'completed' in next_line.lower() and '2022' in next_line:
                            completed_2022.append(line)
                            break
        i += 1

# Deduplicate
completed_2022 = list(set(completed_2022))

# Load funding records and match
